int _mangaChapterEstimateSize(
  MangaChapter object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 + object.chapterId.length * 3;
  bytesCount += 3 + object.pathToChapterData.length * 3;
  bytesCount += 3 + object.seriesId.length * 3;
  bytesCount += 3 + object.title.length * 3;
  return bytesCount;
}

void _mangaChapterSerialize(
  MangaChapter object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.chapterId);
  writer.writeDouble(offsets[1], object.chapterNumber);
  writer.writeString(offsets[2], object.pathToChapterData);
  writer.writeString(offsets[3], object.seriesId);
  writer.writeString(offsets[4], object.title);
  writer.writeLong(offsets[5], object.totalPages);
}

MangaChapter _mangaChapterDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = MangaChapter();
  object.chapterId = reader.readString(offsets[0]);
  object.chapterNumber = reader.readDouble(offsets[1]);
  object.id = id;
  object.pathToChapterData = reader.readString(offsets[2]);
  object.seriesId = reader.readString(offsets[3]);
  object.title = reader.readString(offsets[4]);
  object.totalPages = reader.readLong(offsets[5]);
