int _playableFileEstimateSize(
  PlayableFile object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  {
    final value = object.fileId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  bytesCount += 3 + object.filePath.length * 3;
  bytesCount += 3 +
      PlayNowStateSchema.estimateSize(
          object.playState, allOffsets[PlayNowState]!, allOffsets);
  bytesCount += 3 +
      RatingSchema.estimateSize(object.rating, allOffsets[Rating]!, allOffsets);
  bytesCount += 3 +
      PlayUrlsSchema.estimateSize(
          object.urls, allOffsets[PlayUrls]!, allOffsets);
  bytesCount += 3 +
      PlayStateSchema.estimateSize(
          object.watchState, allOffsets[PlayState]!, allOffsets);
  return bytesCount;
}

void _playableFileSerialize(
  PlayableFile object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.fileId);
  writer.writeString(offsets[1], object.filePath);
  writer.writeBool(offsets[2], object.isVideo);
  writer.writeObject<PlayNowState>(
    offsets[3],
    allOffsets,
    PlayNowStateSchema.serialize,
    object.playState,
  );
  writer.writeObject<Rating>(
    offsets[4],
    allOffsets,
    RatingSchema.serialize,
    object.rating,
  );
  writer.writeObject<PlayUrls>(
    offsets[5],
    allOffsets,
    PlayUrlsSchema.serialize,
    object.urls,
  );
  writer.writeObject<PlayState>(
    offsets[6],
    allOffsets,
    PlayStateSchema.serialize,
    object.watchState,
  );
}

