int _seasonEstimateSize(
  Season object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  bytesCount += 3 +
      MetaDataSchema.estimateSize(
          object.metaData, allOffsets[MetaData]!, allOffsets);
  {
    final value = object.seasonId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  {
    final value = object.seriesId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  return bytesCount;
}

void _seasonSerialize(
  Season object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeObject<MetaData>(
    offsets[0],
    allOffsets,
    MetaDataSchema.serialize,
    object.metaData,
  );
  writer.writeString(offsets[1], object.seasonId);
  writer.writeLong(offsets[2], object.seasonNumber);
  writer.writeString(offsets[3], object.seriesId);
}

Season _seasonDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = Season();
  object.id = id;
  object.metaData = reader.readObjectOrNull<MetaData>(
        offsets[0],
        MetaDataSchema.deserialize,
        allOffsets,
      ) ??
      MetaData();
  object.seasonId = reader.readStringOrNull(offsets[1]);
  object.seasonNumber = reader.readLong(offsets[2]);
  object.seriesId = reader.readStringOrNull(offsets[3]);
  return object;
}

P _seasonDeserializeProp<P>(
  IsarReader reader,
  int propertyId,
  int offset,
