int _episodeEstimateSize(
  Episode object,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  var bytesCount = offsets.last;
  {
    final value = object.details;
    if (value != null) {
      bytesCount += 3 +
          EpisodeDetailsSchema.estimateSize(
              value, allOffsets[EpisodeDetails]!, allOffsets);
    }
  }
  {
    final value = object.episodeId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  bytesCount += 3 +
      MetaDataSchema.estimateSize(
          object.metaData, allOffsets[MetaData]!, allOffsets);
  {
    final value = object.playableFileId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  {
    final value = object.seasonId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  {
    final value = object.seriesId;
    if (value != null) {
      bytesCount += 3 + value.length * 3;
    }
  }
  return bytesCount;
}

void _episodeSerialize(
  Episode object,
  IsarWriter writer,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeObject<EpisodeDetails>(
    offsets[0],
    allOffsets,
    EpisodeDetailsSchema.serialize,
    object.details,
  );
  writer.writeString(offsets[1], object.episodeId);
  writer.writeLong(offsets[2], object.episodeIndex);
  writer.writeObject<MetaData>(
    offsets[3],
    allOffsets,
    MetaDataSchema.serialize,
    object.metaData,
  );
  writer.writeString(offsets[4], object.playableFileId);
  writer.writeString(offsets[5], object.seasonId);
  writer.writeString(offsets[6], object.seriesId);
}

Episode _episodeDeserialize(
  Id id,
  IsarReader reader,
  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  final object = Episode();
  object.details = reader.readObjectOrNull<EpisodeDetails>(
    offsets[0],
    EpisodeDetailsSchema.deserialize,
    allOffsets,
  );
  object.episodeId = reader.readStringOrNull(offsets[1]);
  object.episodeIndex = reader.readLong(offsets[2]);
  object.id = id;
  object.metaData = reader.readObjectOrNull<MetaData>(
        offsets[3],
        MetaDataSchema.deserialize,
        allOffsets,
      ) ??
      MetaData();
  object.playableFileId = reader.readStringOrNull(offsets[4]);
  object.seasonId = reader.readStringOrNull(offsets[5]);
  object.seriesId = reader.readStringOrNull(offsets[6]);
  return object;
}

